appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    const rawData = model.cookies || {};
    const components = rawData.components || {};
    const summary = components.summary || {};
    const byType = summary.by_type || {};
    const byProvider = summary.by_provider || {};
    const crossFileData = rawData.cross_file || {};
    const detections = components.detections || [];

    // --- 1. Aggregating Top-Level Metrics ---
    const boundaryCrossings = crossFileData.ai_boundaries || 0;
    const eligibilityViolations = rawData.crossings?.prohibited_count || 0;
    const undeclaredComponents = (byType.llm_framework?.count || 0) + (byType.agent?.count || 0);
    const serializationTypes = ['Pickle', 'Joblib', 'H5', 'PT', 'Safetensors'];
    let artifactCount = 0;
    let activeVendorCount = 0;
    Object.entries(byProvider).forEach(([name, count]) => {
      if (serializationTypes.includes(name)) {
        artifactCount += count;
      } else if (name !== 'Various') {
        activeVendorCount++;
      }
    });

    // Recreating Exposure Index (From Frame 3 logic)
    const boundaryPenalty = boundaryCrossings * 10;
    const vendorPenalty = activeVendorCount * 5;
    const frameworkPenalty = undeclaredComponents * 2;
    const serializationPenalty = artifactCount > 0 ? 10 + artifactCount * 1 : 0;
    const eligibilityPenalty = eligibilityViolations * 20;
    const rawScore = boundaryPenalty + vendorPenalty + frameworkPenalty + serializationPenalty + eligibilityPenalty;
    const indexScore = Math.min(100, rawScore);

    // Update UI KPI Cards
    document.getElementById('exec-exposure-index').innerText = `${indexScore}/100`;
    document.getElementById('exec-boundary-crossings').innerText = boundaryCrossings;
    document.getElementById('exec-violations').innerText = eligibilityViolations;
    document.getElementById('exec-artifacts').innerText = artifactCount;

    // Change Index color dynamically based on severity
    const indexEl = document.getElementById('exec-exposure-index');
    if (indexScore > 75) indexEl.style.color = '#c0392b';else if (indexScore > 40) indexEl.style.color = '#f39c12';else indexEl.style.color = '#27ae60';

    // --- 2. Generate Executive Findings (Integrating Frame 4/5 Contexts) ---
    const findingsList = document.getElementById('findings-list');
    findingsList.innerHTML = '';
    const findings = [];
    if (eligibilityViolations > 0) {
      findings.push(`<strong>Data Ingestion Signal:</strong> Detected restricted data flows passing from orchestration layers directly into execution environments without explicit eligibility validation.`);
    }
    if (boundaryCrossings > 0) {
      findings.push(`<strong>Hard-coded secret or API key:</strong> 1 secret hardcoded in environment variables in a production environment.`);
    }
    findings.push(`<strong>Boundary Exposure:</strong> ${boundaryCrossings} data paths bypass the agent exposure layer, crossing directly into external Model Inference boundaries.`);
    if (artifactCount > 0) {
      findings.push(`<strong>Supply Chain Risk:</strong> ${artifactCount} instances of serialization formats (Pickle, Joblib, etc.) detected, creating high exposure to arbitrary code execution.`);
    }
    if (undeclaredComponents > 0) {
      findings.push(`<strong>Governance Drift:</strong> ${undeclaredComponents} undeclared AI frameworks or agent tool executions require policy mapping.`);
    }
    if (findings.length === 0) {
      findingsList.innerHTML = '<li style="color: #27ae60;">No critical execution dependencies or boundary violations detected.</li>';
    } else {
      findings.forEach(f => {
        const li = document.createElement('li');
        li.innerHTML = f;
        findingsList.appendChild(li);
      });
    }

    // --- 3. Populate High Priority Action Items Table ---
    const tbody = document.getElementById('exec-table-body');
    tbody.innerHTML = '';

    // Filter and map high priority items across the different risk vectors
    const actionItems = [];
    if (eligibilityViolations > 0) {
      actionItems.push({
        cat: 'Data Eligibility',
        ctx: 'Agent Orchestration Layer',
        badge: 'badge-critical',
        severity: 'Critical',
        action: 'Implement PII/Restricted data validation gates before inference.'
      });
    }

    // Scan for worst detections
    detections.forEach(det => {
      if (det.type === 'model_artifact') {
        actionItems.push({
          cat: 'Artifact Serialization',
          ctx: det.name,
          badge: 'badge-critical',
          severity: 'Critical',
          action: 'Migrate to Safetensors or sign model payloads.'
        });
      } else if (det.type === 'rag') {
        actionItems.push({
          cat: 'RAG Boundary Crossing',
          ctx: det.name,
          badge: 'badge-warning',
          severity: 'High',
          action: 'Review retrieval egress bounds.'
        });
      }
    });

    // Deduplicate and limit to top 5
    const uniqueItems = [...new Map(actionItems.map(item => [item.ctx, item])).values()].slice(0, 5);
    if (uniqueItems.length === 0) {
      tbody.innerHTML = '<tr><td colspan="4" style="text-align: center;">No immediate actions required.</td></tr>';
      return;
    }
    uniqueItems.forEach(item => {
      const tr = document.createElement('tr');
      const tdCat = document.createElement('td');
      tdCat.innerHTML = `<strong>${item.cat}</strong>`;
      const tdCtx = document.createElement('td');
      tdCtx.innerHTML = `<code>${item.ctx}</code>`;
      const tdSeverity = document.createElement('td');
      tdSeverity.innerHTML = `<span class="badge ${item.badge}">${item.severity}</span>`;
      const tdAction = document.createElement('td');
      tdAction.textContent = item.action;
      tr.appendChild(tdCat);
      tr.appendChild(tdCtx);
      tr.appendChild(tdSeverity);
      tr.appendChild(tdAction);
      tbody.appendChild(tr);
    });
  });
});

